SELECT t, groupArray((category, max_0_PerSecond)) AS groupArr FROM ( SELECT t, category, if(runningDifference(max_0) < 0 OR neighbor(category,-1,category) != category, nan, runningDifference(max_0) / runningDifference(t/1000)) AS max_0_PerSecond FROM ( SELECT (intDiv(toUInt32(event_time), 30) * 30) * 1000 AS t, category AS category, max(counter) AS max_0 FROM default.test_grafana WHERE event_date >= toDate(1735787045) AND event_date <= toDate(1735790706) AND event_time >= toDateTime(1735787045) AND event_time <= toDateTime(1735790706) GROUP BY t, category ORDER BY category, t)) GROUP BY t ORDER BY t